```rust
const BAR_CHARS: &[char] = &['░', '▒', '▓', '█'];
const EMPTY_CHAR: char = '░';
const FULL_CHAR: char = '█';

fn render_bar(percent: f64, width: usize) -> String {
    let filled = ((percent / 100.0) * width as f64).round() as usize;
    let empty = width - filled;

    format!(
        "{}{}",
        FULL_CHAR.to_string().repeat(filled),
        EMPTY_CHAR.to_string().repeat(empty)
    )
}

fn render_bar_colored(percent: f64, width: usize) -> String {
    let bar = render_bar(percent, width);
    let color = match percent {
        p if p >= 90.0 => Color::Red,
        p if p >= 70.0 => Color::Yellow,
        _ => Color::Green,
    };
    colorize(&bar, color)
}
```

### Sparkline Renderer

```rust
const SPARKLINE_CHARS: &[char] = &[
    '▁', '▂', '▃', '▄', '▅', '▆', '▇', '█'
];

fn render_sparkline(values: &[f64]) -> String {
    if values.is_empty() {
        return String::new();
    }

    let min = values.iter().cloned().fold(f64::INFINITY, f64::min);
    let max = values.iter().cloned().fold(f64::NEG_INFINITY, f64::max);
    let range = max - min;

    values.iter()
        .map(|&v| {
            let normalized = if range > 0.0 { 
                (v - min) / range 
            } else { 
                0.5 
            };
            let idx = (normalized * 7.0).round() as usize;
            SPARKLINE_CHARS[idx.min(7)]
        })
        .collect()
}
```

### Trend Indicator

```rust
fn render_trend(current_avg: f64, previous_avg: f64) -> String {
    let change_pct = ((current_avg - previous_avg) / previous_avg) * 100.0;

    let (arrow, color) = match change_pct {
        c if c > 10.0 => ('↗', Color::Red),      // Bad: usage increasing
        c if c > 2.0 => ('↗', Color::Yellow),
        c if c < -10.0 => ('↘', Color::Green),   // Good: usage decreasing
        c if c < -2.0 => ('↘', Color::Green),
        _ => ('→', Color::White),                // Stable
    };

    format!("{} {:+.1}%", colorize(&arrow.to_string(), color), change_pct)
}
```

