            day.date.format("%a %m/%d"),
            bar,
            day.avg_primary_pct,
            cost,
            marker
        );
    }

    println!();

    // Summary line with sparkline
    let values: Vec<f64> = snapshots.iter().map(|d| d.avg_primary_pct).collect();
    let sparkline = render_sparkline(&values);
    let trend = render_trend(current_period_avg, previous_period_avg);

    println!("Trend: {}  {}", sparkline, trend);
}
