    fn parse(&self, response: &str) -> Result<ProviderStatus> {
        let google: GoogleIncidents = serde_json::from_str(response)?;

        // Filter to relevant services (Vertex AI)
        let relevant = google.incidents.iter()
            .filter(|i| i.service_key == "vertex-ai")
            .filter(|i| i.status != "resolved");

        // Map severity to StatusIndicator
        let indicator = match relevant.map(|i| &i.severity).max() {
            Some("high") => StatusIndicator::Major,
            Some("medium") => StatusIndicator::Minor,
            _ => StatusIndicator::None,
        };

        Ok(ProviderStatus { indicator, ... })
    }
